def solve(nums: Array[Long], k: Long): Long = {
    val n = nums.length
    nums.sort()
    var maxLen = 1L
    for (i <- 0 until n) {
        val target = nums(i) * k
        var low = i
        var high = n - 1
        var bestJ = i - 1
        while (low <= high) {
            val mid = (low + high) / 2
            if (nums(mid) <= target) {
                bestJ = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        val currentLen = bestJ - i + 1
        if (currentLen > maxLen) {
            maxLen = currentLen
        }
    }
    n - maxLen
}
